const childWorkflows = ['CWF-210', 'CWF-220', 'CWF-230', 'CWF-240'];
let executionPlan = { workflows_to_execute: childWorkflows, current_index: 0, status: 'PLANNING', decisions: { quality_gate: true, governance_gate: true } };
return [{ json: { ...$json, execution_plan: executionPlan, pack_orchestration: { started_at: new Date().toISOString(), expected_duration_seconds: 180 } } }];

const childResults = { CWF_210: $json.cwf210_result, CWF_220: $json.cwf220_result, CWF_230: $json.cwf230_result, CWF_240: $json.cwf240_result };
const allHealthy = Object.values(childResults).every(r => r?.status === 'SUCCESS' || r?.status === 'COMPLETED');
const scriptFinalized = $json.cwf240_result?.payload?.final_script_finalized === true;
const qualityApproved = $json.cwf240_result?.payload?.quality_gates_passed === true;
const validationOk = allHealthy && scriptFinalized && qualityApproved;
return [{ json: { ...$json, pack_validation: { child_results_aggregated: childResults, all_children_healthy: allHealthy, script_finalized: scriptFinalized, quality_approved: qualityApproved, validation_ok: validationOk, route_to_error: !validationOk } } }];

if ($json.pack_validation.route_to_error) return [];
return [{
  json: {
    ...$json,
    dossier_write: {
      mutation_type: 'namespace_update',
      target: 'dossier.script',
      timestamp: new Date().toISOString(),
      writer_id: 'WF-200',
      pack_context: $json.pack_context,
      child_results: $json.pack_validation.child_results_aggregated,
      audit_entry: 'script-intelligence-pack-completion from WF-200'
    }
  }
}];

if ($json.pack_validation.route_to_error) return [];
return [{
  json: {
    ...$json,
    se_route_runs_write: {
      operation: 'record_pack_execution',
      pack_id: 'WF-200',
      dossier_id: $json.dossier_id,
      child_workflows_executed: ['CWF-210', 'CWF-220', 'CWF-230', 'CWF-240'],
      execution_status: 'COMPLETED',
      script_finalized: $json.pack_validation.script_finalized,
      quality_approved: $json.pack_validation.quality_approved,
      timestamp: new Date().toISOString()
    }
  }
}];

if ($json.pack_validation.route_to_error) return [];
return [{
  json: {
    workflow_id: 'WF-200',
    execution_status: 'SUCCESS',
    completion_packet: {
      instance_id: 'WF-200-COMP-' + Date.now(),
      artifact_family: 'script_intelligence_result',
      schema_version: '1.0.0',
      producer_workflow: 'WF-200',
      dossier_ref: $json.dossier_id,
      created_at: new Date().toISOString(),
      status: 'CREATED',
      payload: {
        pack_executed: 'WF-200',
        script_finalized: $json.pack_validation.script_finalized,
        quality_approved: $json.pack_validation.quality_approved,
        next_workflow: 'WF-300',
        child_packets: ['CWF-210_output', 'CWF-220_output', 'CWF-230_output', 'CWF-240_output']
      }
    }
  }
}];

if (!$json.pack_validation.route_to_error) return [];
return [{
  json: {
    workflow_id: 'WF-200',
    routing_decision: 'ERROR',
    route_to_workflow: 'WF-900',
    error_message: 'Pack validation failed or child workflow failed',
    failure_context: $json.pack_validation,
    child_results: $json.pack_validation.child_results_aggregated
  }
}];
